"""Inspect full_trajectories.pt generated by generate_dataset.py.

Usage:
    python scripts/inspect_trajectories.py
    python scripts/inspect_trajectories.py --path scm_ds/predictor_dataset/trajectories/full_trajectories.pt
    python scripts/inspect_trajectories.py --index 5
    python scripts/inspect_trajectories.py --all
"""

import argparse
from pathlib import Path

import numpy as np
import torch


def main():
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument(
        '--path', type=str,
        default='scm_ds/predictor_dataset/trajectories/full_trajectories.pt',
        help='Path to full_trajectories.pt',
    )
    parser.add_argument('--index', type=int, default=0,
                        help='Index of trajectory to print in detail')
    parser.add_argument('--all', action='store_true',
                        help='Print every trajectory (verbose)')
    args = parser.parse_args()

    path = Path(args.path)
    if not path.exists():
        raise FileNotFoundError(
            f'{path} not found. Run `python generate_dataset.py` first.'
        )

    trajs = torch.load(str(path), weights_only=False)
    n = len(trajs)
    proc_names = list(trajs[0]['trajectory'].keys())
    F_vals = np.array([t['F'] for t in trajs], dtype=np.float64)

    print('=' * 70)
    print(f'File: {path}')
    print('=' * 70)
    print(f'# trajectories : {n}')
    print(f'processes      : {proc_names}')
    print(f'F stats        : mean={F_vals.mean():.4f}  '
          f'std={F_vals.std():.4f}  '
          f'min={F_vals.min():.4f}  max={F_vals.max():.4f}')

    print('\nShapes (from first trajectory):')
    for pname, pdata in trajs[0]['trajectory'].items():
        print(f'  {pname}: '
              f'inputs={tuple(pdata["inputs"].shape)}  '
              f'env={tuple(pdata["env"].shape)}  '
              f'outputs={tuple(pdata["outputs"].shape)}')

    indices = range(n) if args.all else [args.index]
    for i in indices:
        if i < 0 or i >= n:
            print(f'\n[!] Index {i} out of range (0..{n - 1})')
            continue
        t = trajs[i]
        print('\n' + '-' * 70)
        print(f'Trajectory #{i}   F = {t["F"]:.6f}')
        print('-' * 70)
        for pname, pdata in t['trajectory'].items():
            print(f'  [{pname}]')
            print(f'    inputs : {pdata["inputs"].tolist()}')
            print(f'    env    : {pdata["env"].tolist()}')
            print(f'    outputs: {pdata["outputs"].tolist()}')


if __name__ == '__main__':
    main()
